            // 
            // TotalCostPerc_CF
            // 
            this.TotalCostPerc_CF.DataMember = "SR_FM_Stocktaking";
            this.TotalCostPerc_CF.DisplayName = "TotalCostPerc_CF";
            this.TotalCostPerc_CF.Expression = "(ToDecimal([TotalCost]) / ToDecimal(Sum([TotalCost])))*ToDecimal(100)\n";
            this.TotalCostPerc_CF.Name = "TotalCostPerc_CF";
            // 
            // Per_Chick_CF
            // 
            this.Per_Chick_CF.DataMember = "SR_FM_Stocktaking";
            this.Per_Chick_CF.Expression = "Iif([FemaleChicks]!=0,[TotalCost]/[FemaleChicks] ,[FemaleChicks] )";
            this.Per_Chick_CF.Name = "Per_Chick_CF";
            // 
            // PerHH_CF
            // 
            this.PerHH_CF.DataMember = "SR_FM_Stocktaking";
            this.PerHH_CF.DisplayName = "PerHH_CF";
            this.PerHH_CF.Expression = "Iif([FemalePOL]!=0,[TotalCost]/[FemalePOL] ,[FemalePOL] )\n";
            this.PerHH_CF.Name = "PerHH_CF";
            // 
            // PerHE_CF
            // 
            this.PerHE_CF.DataMember = "SR_FM_Stocktaking";
            this.PerHE_CF.Expression = "Iif([HatchingEggs]!=0,[TotalCost]/[HatchingEggs] ,[HatchingEggs] )\n\n";
            this.PerHE_CF.Name = "PerHE_CF";
            // 
            // DiffQtyq
            // 
            this.DiffQtyq.DataMember = "SR_FM_Stocktaking";
            this.DiffQtyq.Expression = "IsNull([ActualQty], 0) - IsNull([SentOrClacQty], 0)";
            this.DiffQtyq.Name = "DiffQtyq";
            // 
            // DiffPriceq
            // 
            this.DiffPriceq.DataMember = "SR_FM_Stocktaking";
            this.DiffPriceq.Expression = "Iif([CalcPriceUnit] > 0, IsNull([AdjustedPriceUnit], 0) - IsNull([CalcPriceUnit]," +
    " 0), 0)";
            this.DiffPriceq.Name = "DiffPriceq";
            // 
            // ActEggRecHHCum
            // 
            this.ActEggRecHHCum.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.ActEggRecHHCum.Expression = "Iif([SR_HT_WeeklyHHFlockSum.POL] <> 0, [SR_HT_WeeklyHHFlockSum.ActRecEggs] / [SR_" +
    "HT_WeeklyHHFlockSum.POL], 0)\n";
            this.ActEggRecHHCum.Name = "ActEggRecHHCum";
            // 
            // RejEggHHCum
            // 
            this.RejEggHHCum.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.RejEggHHCum.Expression = "Iif([SR_HT_WeeklyHHFlockSum.POL] <> 0, [SR_HT_WeeklyHHFlockSum.RejEggs] / [SR_HT_" +
    "WeeklyHHFlockSum.POL], 0)\n";
            this.RejEggHHCum.Name = "RejEggHHCum";
            // 
            // EstHatEggs
            // 
            this.EstHatEggs.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.EstHatEggs.Expression = "[ActEggRecHHCum] - [RejEggHHCum]\n";
            this.EstHatEggs.Name = "EstHatEggs";
            // 
            // ActEggSetHHCum
            // 
            this.ActEggSetHHCum.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.ActEggSetHHCum.Expression = "Iif([SR_HT_WeeklyHHFlockSum.POL] <> 0, [SR_HT_WeeklyHHFlockSum.ActSetEggCum] / [S" +
    "R_HT_WeeklyHHFlockSum.POL], 0)\n";
            this.ActEggSetHHCum.Name = "ActEggSetHHCum";
            // 
            // EstHatEggsBefore21days
            // 
            this.EstHatEggsBefore21days.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.EstHatEggsBefore21days.Expression = "[SR_HT_WeeklyHHFlockSum.ActRecEggsBefore21days] - [SR_HT_WeeklyHHFlockSum.RejEggs" +
    "Before21days]\n";
            this.EstHatEggsBefore21days.Name = "EstHatEggsBefore21days";
            // 
            // ActHatch_Per_Cum
            // 
            this.ActHatch_Per_Cum.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.ActHatch_Per_Cum.Expression = resources.GetString("ActHatch_Per_Cum.Expression");
            this.ActHatch_Per_Cum.Name = "ActHatch_Per_Cum";
            // 
            // EstChiks
            // 
            this.EstChiks.DataMember = "SR_HT_WeeklyHHFlockSum";
            this.EstChiks.Expression = "Iif([SR_HT_WeeklyHHFlockSum.POL] > 0, \n    ([EstHatEggsBefore21days] * [ActHatch_" +
    "Per_Cum] / 100) / [SR_HT_WeeklyHHFlockSum.POL], \n    0)\n";
            this.EstChiks.Name = "EstChiks";
            // 
            // ActChicksHHCum
            // 
